{
	cudaDeviceProp prop;
	gpuErrchk(cudaGetDeviceProperties(&prop, device));

	int runtimeVersion = 0;
	gpuErrchk(cudaRuntimeGetVersion(&runtimeVersion));

	printf("Device: %s\n", prop.name);
	printf(" %d Hardware version: %d.%d\n", 1, prop.major, prop.minor);
	printf(" %d Software version: %d.%d\n", 2, runtimeVersion / 1000, (runtimeVersion % 100) / 10);
	printf(" %d OpenCL C version: %s\n", 3, "N/A");
	printf(" %d Parallel compute units: %d\n", 4, prop.multiProcessorCount);
}

